const sep    = '-'.repeat(header.length);

const lines = mapped.map(r =>
  `${pad(r.referencia, W_MES-2)} ${padR(numBR(r.leitura), W_LEI)} ${padR(numBR(r.consumo), W_CONS)}`
);

const reply =
