/**
 * ROUTER — Ident (Nome -> Código), Menu e Confirmação SIM/NÃO
 * Entradas principais: j.message.content.data (Get Payload), j._session (Select/Inject Sessão)
 * Saídas: j.session, j.reply, j.showMenu (bool), j.showEnd (bool), j.finalize (bool)
 */

// --- Header
const item = $input.item || { json: {} };
const j = item.json || {};

// util: primeiro texto não vazio
const first = (...vals) => {
  for (const v of vals)
    if (typeof v === "string" && v.trim() !== "") return v.trim();
  return "";
};
const lower = (s) => (s || "").toLowerCase();

// -------- Entrada normalizada (Get Payload) --------
const data = j?.message?.content?.data || {};
const textIn = first(data.text);
const listT = data?.list?.title || null;
const listId = data?.list?.rowId || null;
const btnLabel = data?.button?.label || null;

j.isList = !!(listT || listId);
j.choiceTitle = listT;
j.choiceId = listId;

// mensagem efetiva
let msg = j.isList ? j.choiceTitle || "" : textIn;

const normalized = String(msg).trim().toLowerCase();

// comandos globais
if (normalized.includes("sair")) {
  j.showEnd = true;
  // Obtém a hora atual de Brasília
  const agora = new Date();
  const horaBR = new Date(agora.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
  const hora = horaBR.getHours();
  let mensagem;
  if (hora <= 12) {
    mensagem = "*Agradecemos pelo contato*, tenha um ótimo dia ☀️";
  } else if (hora >= 18) {
    mensagem = "*Agradecemos pelo contato*, tenha uma ótima noite 🌃";
  } else {
    mensagem = "*Agradecemos pelo contato*, tenha uma ótima tarde 🌇";
  }
  j.reply = mensagem;
  return item;
}

// phone robusto
const src = ($items("Receber mensagem")[0] || {}).json || {};
j.phone = j.phone ?? j?.body?.phone ?? data?.phone ?? src?.body?.phone ?? null;


// -------- Reconstroi sessão a partir do Select/Inject Sessão --------
const row = j._session || {};
let session = null;
if (row && (row.flow || row.data_json || row.expires_at)) {
  session = {
    phone: row.phone || j.phone,
    phoneconectado: row.phoneconectado || j.phoneconectado,
    flow: row.flow || "ident",
    step: Number(row.step ?? 1),
    expectedRef: row.expected_ref ?? row.expectedRef ?? null,
    data: row.data_json
      ? typeof row.data_json === "string"
        ? JSON.parse(row.data_json || "{}") || {}
        : row.data_json
      : {},
    expiresAt: row.expires_at
      ? new Date(row.expires_at).toISOString()
      : null,
  };
}

// expiração & resets
if (session?.expiresAt && new Date(session.expiresAt) < new Date())
  session = null;
const low = lower(msg);
if (low === "menu" || low === "cancelar") session = null;

// ===================== NÃO AUTENTICADO (ident) =====================
const authed = session?.data?.authOk === true;

if (!authed) {
  if (!session || session.flow !== "ident") {
    // inicia identificação
    session = {
      phone: j.phone,
      phoneconectado: j.phoneconectado,
      flow: "ident",
      step: 1,
      data: {},
      expectedRef: null,
      expiresAt: new Date(Date.now() + 15 * 60000).toISOString(),
    };
    j.reply = "👋🏻 Olá! Eu sou o *BILL*, seu assistente virtual.\nEstou aqui para te atender de forma rápida e humanizada.\n\nPara começarmos, qual é o seu *nome*?";
    j.finalize = false;
  } else if (session.step === 1 && !j.reply) {
    // PASSO 1 — nome
    if (msg === "") {
      j.reply = "Desculpe, não consegui entender.\nPode me informar seu *nome*, por favor? 🙌🏻";
    } else {
      session.data.nome = msg;
      session.step = 2;
      session.needValidateLigacao = false; // só arma quando vier o código
        j.reply = `Prazer em falar com você, *${session.data.nome} !* 👋🏻\nPor favor, me informe o *código da ligação* (apenas os números, sem o dígito).\n\nSe quiser encerrar o atendimento, basta digitar *Sair* a qualquer momento.`;
    }
    j.finalize = false;
  } 

  else if (session.step === 2 && !j.reply) {
  const codigodaLigacao = String(msg ?? "").trim();

  if (codigodaLigacao === "") {
    j.reply = `Informe o *código da ligação*.`;
    j.finalize = false;
  } else if (!/^[0-9]+$/.test(codigodaLigacao)) {        // <-- só passa se for SÓ números
    j.reply = "O código informado não é válido.\n\nPor favor, digite apenas os *números* — sem letras, espaços ou símbolos. 🔢";
    j.finalize = false;
  } else {
      session.data.codigoLigacao = codigodaLigacao;        // mantém exatamente o que foi digitado (só dígitos)
      session.step = 3;
      session.needValidateLigacao = false; 
      j.reply =`*${session.data.nome}*, me informe por favor a *chave digital*.`;
    j.finalize = false;
  }
}   

  else if (session.step === 3 && !j.reply) {
  const chavedigital = String(msg ?? "").trim();
  if (chavedigital === "") {
    j.reply = "Informe a *chave digital*.";
    j.finalize = false;
  } else {
      session.data.chavedigital = chavedigital;        // mantém exatamente o que foi digitado (só dígitos)
      session.step = 3;
      session.needValidateLigacao = true; 
      j.reply = null;
    j.finalize = false;
  }
}

  // saída parcial
  session.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();
  j.session = {
    phone: session.phone,
    phoneconectado: session.phoneconectado,
    flow: session.flow,
    step: session.step,
    expectedRef: session.expectedRef,
    data: session.data,
    expiresAt: session.expiresAt,
    needValidateLigacao: !!session.needValidateLigacao,
  };
  return item;
}

// ===================== AUTENTICADO =====================

// SIM/NÃO (quando estiver em confirmação)
const ans = lower(btnLabel || j.choiceTitle || msg || "");
const isYesNo = ans === "sim" || ans === "não";


if (session?.flow === "humano")
{
      session.flow = "ident",
      session.step = 3;
      session.needValidateLigacao = true; 
      j.reply = null;
}

if (session?.flow === "confirm" && session?.step === 1 && isYesNo) {
  if (ans === "sim") {
    session.step = 0;
    j.showMenu = true; // lista será enviada fora do Router
    j.reply = "";
  } else {
  // Obtém a hora atual de Brasília
  const agora = new Date();
  const horaBR = new Date(agora.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
  const hora = horaBR.getHours();

  // Define a mensagem conforme o horário
  let mensagem;
  if (hora <= 12) {
    mensagem = "*Agradecemos pelo contato*, tenha um ótimo dia ☀️";
  } else if (hora >= 18) {
    mensagem = "*Agradecemos pelo contato*, tenha uma ótima noite 🌃";
  } else {
    mensagem = "*Agradecemos pelo contato*, tenha uma ótima tarde 🌇";
  }
  // Retorna valores no padrão da tua sessão
  session.step = 0;
  j.showEnd = true;
  j.reply = mensagem;
}
  session.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();
  j.session = session;
  return item;
}

// Escolha de serviço (autenticado)
const chosen = lower(j.isList ? j.choiceTitle : msg || "");

if (chosen === "localização") {
  j.reply = null; // fluxo de Localização assume
} else if (chosen.includes("denúncia") || chosen.includes("denuncia")) {
  j.reply = "Tudo certo! 💬\n\nMe conte com o máximo de detalhes o que aconteceu, assim conseguimos te ajudar mais rápido.";
  session.flow = "ouvidoria";
} else if (
  chosen === "histórico de consumo" ||
  chosen === "historico de consumo"
) {
  j.reply = null; // fluxo histórico assume
} else if (
  chosen === "2ª via de fatura" ||
  chosen === "2ª via" ||
  chosen === "faturas em aberto"
) {
  // mantém seu comportamento atual; se quiser PIX, trate aqui (flow='pix')
  j.reply = null;
}

// Atualiza sessão e sai
session.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();
j.session = {
  phone: session.phone,
  phoneconectado: session.phoneconectado,
  flow: session.flow,
  step: session.step,
  expectedRef: session.expectedRef,
  data: session.data,
  expiresAt: session.expiresAt,
  needValidateLigacao: !!session.needValidateLigacao,
};

return item;

const j = $input.item.json;
const sess = j.session || {};
sess.data = sess.data || {};

let codigo = String(sess.data.codigoLigacao ?? j.codigo ?? '').trim();
codigo = (codigo.match(/\d+/g)?.join('')) || '';
if (codigo) sess.data.codigoLigacao = codigo;
else delete sess.data.codigoLigacao;

return [{ json: { phone: j.phone, session: sess } }];

// -------- Processa Validação (após MERGE) --------
const j = $input.item.json || {};
const sess = j.session || {};
const phone = j.phone || sess.phone || null;

const found = Number(j.found ?? j.matricula != null) === 1;
const nome = sess?.data?.nome || "cliente";
const codigo = sess?.data?.codigoLigacao || j.codigo || "";

if (found) {
  sess.data = sess.data || {};
  sess.data.authOk = true;
  sess.flow = "menu";
  sess.step = 0;
  sess.needValidateLigacao = false;
  sess.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();
  sess.data.codigoLigacao = codigo;
  sess.data.nome = nome;

const cab = `Tudo certo, *` + nome + `*!✅\n\nValidei a ligação *` + codigo + `*.\n\nEsta ligação está vinculada ao endereço : *` + $input.first().json.rua + `*, número *XXX*, *` + $input.first().json.bairro + `*.\n\nQue bom ter você por aqui !\nEm que posso lhe ajudar ?`;
  return [{ json: { phone, session: sess, showMenu: true, reply: cab } }];
}

// NÃO ENCONTROU → sempre devolve texto
sess.step = 2;
sess.needValidateLigacao = true;
sess.expiresAt = new Date(Date.now() + 15 * 60000).toISOString();

const msg =
  "Parece que o código da ligação ou a chave digital não conferem, confirme as informações.\n\nPor favor, digite novamente o *código da ligação* (apenas os números, sem o dígito). 🔁";
return [{ json: { phone, session: sess, showMenu: false, reply: msg } }];

const item = $input.item;
const j = item.json;

// ==== ENTRADA / CAMPOS ÚTEIS (mantidos) ====
const b = j.body ?? {};
j.phone = j.phone ?? b.phone ?? null;

// veio resposta de lista/botão?
j.listResponse = !!(b.listResponseMessage || b.listResponse || b.buttonReply);

// flag “encerrar atendimento” quando clicado em “Não”
const btnMsg = (b?.buttonReply?.message ?? "").trim().toLowerCase();
j.encerraratendimento = btnMsg === "não";

// ==== CONFIGURAÇÃO POR NÚMERO (adicione seus números aqui) ====
// Use apenas dígitos no índice, exatamente como chega em j.PhoneConnected
const phonesConfig = {
  553798334700: {
    idInstanceZapi: "3EA6B3979B12E1B6EDC772620DC9C8F4",
    tokenInstanceZapi: "86D7C5F85892C2570C026339",
    clientTokenHeaderZapi: "Fdc4b6b51b6d942db941b9e00a4991740S",
    rotaPrincipalDados: "https://demonstracao.agenciavirtual.api.gestaosaneamentoweb.com.br/api/chatbot",
    title: "Inovação Computação Móvel",
