  },
  553798603941: {
    idInstanceZapi: "3E8020BFCB6F329C7878B2948C7C07B3",
    tokenInstanceZapi: "7FAEC497FAA217714D1F22C7",
    clientTokenHeaderZapi: "Fdc4b6b51b6d942db941b9e00a4991740S",
    rotaPrincipalDados:
      "https://tdev-ag.icommercial002.inovamobil.com.br/api/chatbot",
    title: "Residência",
    address: "Rua Itapecerica, 1060, Sidil, Divinopolis, MG, 35500-018",
