    long: "-44.88389",
    tipoRequerimento: 22,
  },
};

// ==== OBRIGATÓRIO TER PhoneConnected ====
const phoneConnected = (j.PhoneConnected ?? "").replace(/\D+/g, "");
const selected = phonesConfig[phoneConnected];
if (!selected) {
  throw new Error(
    `PhoneConnected (${phoneConnected || "vazio"}) não mapeado em phonesConfig`,
  );
}

// ==== PARAMS (nomes mantidos, sem impacto) ====
const idInstanceZapi = selected.idInstanceZapi;
const tokenInstanceZapi = selected.tokenInstanceZapi;
const clientTokenHeaderZapi = selected.clientTokenHeaderZapi;
const rotaPrincipalDados = selected.rotaPrincipalDados;

const baseUrl = "https://api.z-api.io";
const extensionDocument = "pdf";

// ==== ENV / ENDPOINTS ====
const endpointZapi = `${baseUrl}/instances/${idInstanceZapi}/token/${tokenInstanceZapi}`;
j.env = {
  baseUrl,
  idInstanceZapi,
  tokenInstanceZapi,
